import{_ as a,o,c as r,ae as t}from"./chunks/framework.BD9pLfSD.js";const g=JSON.parse('{"title":"The CFO Hub: Observer & Control Plane","description":"","frontmatter":{},"headers":[],"relativePath":"docs/guide/hub-overview.md","filePath":"docs/guide/hub-overview.md"}'),n={name:"docs/guide/hub-overview.md"};function l(s,e,i,c,d,h){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="the-cfo-hub-observer-control-plane" tabindex="-1">The CFO Hub: Observer &amp; Control Plane <a class="header-anchor" href="#the-cfo-hub-observer-control-plane" aria-label="Permalink to &quot;The CFO Hub: Observer &amp; Control Plane&quot;">​</a></h1><p>The <strong>Hub</strong> is the central nervous system of the xB77 ecosystem for the human operator. It is a local-first dashboard that provides real-time observability and governance over your autonomous agents.</p><h2 id="_1-commercial-terminal" tabindex="-1">1. Commercial Terminal <a class="header-anchor" href="#_1-commercial-terminal" aria-label="Permalink to &quot;1. Commercial Terminal&quot;">​</a></h2><p>This is the operational view. It allows you to:</p><ul><li><strong>Monitor Activity:</strong> A live feed of agent transactions with &quot;Privacy Toggles&quot; to mask or reveal shielded data.</li><li><strong>Forensic Radar:</strong> A visual scanner that shows the risk assessment performed by the agent before a payment is executed.</li><li><strong>Agent Thought Stream:</strong> A real-time log of the agent&#39;s internal reasoning (e.g., &quot;Analyzing optimal route,&quot; &quot;Risk detected,&quot; &quot;Shielding assets&quot;).</li></ul><h2 id="_2-shadow-governance" tabindex="-1">2. Shadow Governance <a class="header-anchor" href="#_2-shadow-governance" aria-label="Permalink to &quot;2. Shadow Governance&quot;">​</a></h2><p>This panel is the security guardrail. When an agent triggers a <strong>Lockdown Mode</strong>, the transaction appears here.</p><ul><li><strong>Inspect Encrypted Intents:</strong> Decrypt the agent&#39;s intent using a local master key.</li><li><strong>Manual Override:</strong> Approve or Reject high-value transactions that exceed autonomous limits.</li></ul><h2 id="_3-control-plane" tabindex="-1">3. Control Plane <a class="header-anchor" href="#_3-control-plane" aria-label="Permalink to &quot;3. Control Plane&quot;">​</a></h2><p>For developers and operators:</p><ul><li><strong>Agent Management:</strong> Register new MCP agents, inspect their capabilities, and monitor their uptime.</li><li><strong>Process Control:</strong> Spawn or stop agent processes directly from the UI.</li><li><strong>Tool Runner:</strong> Manually trigger any MCP tool (e.g., <code>agent.pay</code>, <code>cfo.treasury.rebalance</code>) to test the system.</li></ul><hr><h1 id="el-hub-del-cfo-plano-de-observacion-y-control-es" tabindex="-1">El Hub del CFO: Plano de Observación y Control (ES) <a class="header-anchor" href="#el-hub-del-cfo-plano-de-observacion-y-control-es" aria-label="Permalink to &quot;El Hub del CFO: Plano de Observación y Control (ES)&quot;">​</a></h1><p>El <strong>Hub</strong> es el panel central para el operador humano. Proporciona observabilidad y gobernanza en tiempo real.</p><h2 id="_1-terminal-comercial" tabindex="-1">1. Terminal Comercial <a class="header-anchor" href="#_1-terminal-comercial" aria-label="Permalink to &quot;1. Terminal Comercial&quot;">​</a></h2><ul><li><strong>Monitoreo:</strong> Feed en vivo con &quot;Toggles de Privacidad&quot;.</li><li><strong>Radar Forense:</strong> Visualización del análisis de riesgo del agente.</li><li><strong>Flujo de Pensamiento:</strong> Registro de la lógica interna del agente.</li></ul><h2 id="_2-gobernanza-en-las-sombras" tabindex="-1">2. Gobernanza en las Sombras <a class="header-anchor" href="#_2-gobernanza-en-las-sombras" aria-label="Permalink to &quot;2. Gobernanza en las Sombras&quot;">​</a></h2><ul><li><strong>Inspección:</strong> Desencripta las intenciones del agente.</li><li><strong>Override:</strong> Aprueba o rechaza transacciones bloqueadas por seguridad.</li></ul><h2 id="_3-plano-de-control" tabindex="-1">3. Plano de Control <a class="header-anchor" href="#_3-plano-de-control" aria-label="Permalink to &quot;3. Plano de Control&quot;">​</a></h2><ul><li><strong>Gestión:</strong> Registra y monitorea agentes MCP.</li><li><strong>Herramientas:</strong> Ejecuta herramientas manualmente para pruebas.</li></ul>',20)])])}const m=a(n,[["render",l]]);export{g as __pageData,m as default};
